import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(a, b):
        return np.linalg.norm(a - b)

    def arrival_time(cost):
        return current_time + cost / truck_speed

    best_node = None
    min_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        d = distance(cur_truck_pos, customer)
        arrival = arrival_time(d)
        time_window_start, time_window_end = time_windows[i]

        if arrival <= time_window_end:
            if arrival < time_window_start:
                arrival = time_window_start  # Wait until the start of the time window

            if arrival < min_time:
                min_time = arrival
                best_node = i

    if best_node is None:
        # No customer can be arrived at within a time window, head towards depot or wait
        depot_arrival = arrival_time(distance(cur_truck_pos, depot_pos))
        return None if depot_arrival > current_time else 'depot'

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def penalty(time, window):
        if time < window[0]:
            return window[0] - time  # Needs waiting
        elif time > window[1]:
            return float('inf')  # Missed time window
        else:
            return 0  # Within time window

    best_node = None
    best_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        arrival_time = current_time + travel_time(cur_truck_pos, customer)
        time_penalty = penalty(arrival_time, time_windows[i])

        if time_penalty == float('inf'):
            continue  # Skip this customer if can't meet time window

        # Calculate heuristic score
        distance_weight = 1.0
        time_penalty_weight = 2.0

        score = (distance_weight * travel_time(cur_truck_pos, customer)) + (time_penalty_weight * time_penalty)

        if score < best_score:
            best_score = score
            best_node = i

    # If best_node is still None, return None to indicate waiting is better
    return best_node

