import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_penalty = float('inf')
    best_node = None

    for i, (customer_pos, time_window) in enumerate(zip(unvisited_customers, time_windows)):
        travel_time = np.linalg.norm(np.array(customer_pos) - np.array(cur_truck_pos)) / truck_speed
        arrival_time = current_time + travel_time
        time_to_wait = max(0, time_window[0] - arrival_time)

        if arrival_time >= time_window[1]:
            penalty = float('inf')
        else:
            penalty = time_to_wait

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    return best_node
